module RefModule(
    input clk,
    input rst,
    output [7:0] count
);

    reg [7:0] unused_shift_reg;

    always @(posedge clk) begin
        if (rst) begin
            unused_shift_reg <= 8'b11111111;
        end else begin
            unused_shift_reg <= {unused_shift_reg[6:0], ~unused_shift_reg[7]};
        end
    end

    assign count = unused_shift_reg;

endmodule
